    70→      ENVOY_LOG(critical, "cannot open admin address output file {} for writing.",
    71→                server_.options().adminAddressPath());
    72→    } else {
    73→      address_out_file << socket_->connectionInfoProvider().localAddress()->asString();
    74→    }
    75→  }
    76→}
